html: <html>
<head>
  <title>Accessible Autocomplete</title>
  <link href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css" rel="stylesheet">
</head>
<body>
  <div class="max-w-md mx-auto p-4 bg-white rounded shadow-md">
    <input id="input" type="text" placeholder="Search..." class="w-full p-2 mb-2 focus:outline-none focus:ring ring-blue-400" autocomplete="off">
    <ul id="list" class="py-2 bg-white border border-gray-200 rounded shadow-md" style="display: none;">
      <li class="py-2 hover:bg-gray-200">Option 1</li>
      <li class="py-2 hover:bg-gray-200">Option 2</li>
      <!-- Add more options here -->
    </ul>
    <p id="selected-value" class="text-lg text-gray-600"></p>
    <script src="script.js"></script>
  </div>
</body>
</html>
css: .option { display: block; padding: 8px; }
.option:hover { background-color: #f0f0f0; }
js: const input = document.getElementById('input');
const list = document.getElementById('list');
const selectedItem = document.getElementById('selected-value');
input.addEventListener('input', (e) => {
  const inputValue = e.target.value.toLowerCase();
  const options = Array.prototype.slice.call(list.children);
  options.forEach((option) => {
    const text = option.textContent.toLowerCase();
    const isVisible = text.includes(inputValue);
    option.style.display = isVisible ? 'block' : 'none';
  });
  const filteredOptions = options.filter((option) => option.style.display !== 'none');
  if (filteredOptions.length > 0) {
    const selectedOption = filteredOptions[0];
    input.value = selectedOption.textContent;
    selectedItem.textContent = selectedOption.textContent;
  } else {
    selectedItem.textContent = '';
  }
});
input.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    const selectedOption = list.children[list.children.length - 1];
    if (selectedOption) {
      input.value = selectedOption.textContent;
      selectedItem.textContent = selectedOption.textContent;
    }
  }
});
input.addEventListener('focus', () => {
  list.style.display = 'block';
});
input.addEventListener('blur', () => {
  list.style.display = 'none';
});
